import{_ as t,c,a1 as a,o as i}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Tấn công DDoS sử dụng HOIC","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md","filePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md"}'),o={name:"vi/categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md"};function h(g,n,e,r,s,u){return i(),c("div",null,n[0]||(n[0]=[a('<h1 id="tan-cong-ddos-su-dung-hoic" tabindex="-1">Tấn công DDoS sử dụng HOIC <a class="header-anchor" href="#tan-cong-ddos-su-dung-hoic" aria-label="Permalink to &quot;Tấn công DDoS sử dụng HOIC&quot;">​</a></h1><p>Một cuộc tấn công từ chối dịch vụ phân tán (DDoS) liên quan đến một nhóm các hệ thống bị xâm phạm, thường bị nhiễm Trojan, được sử dụng để thực hiện tấn công DoS trên một hệ thống hoặc mạng mục tiêu.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Thực hiện tấn công DDoS - HTTP flooding</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux (Mục tiêu)</li><li>Máy ảo Windows Server, Windows 10 và Windows 7 (Kẻ tấn công)</li></ul><h3 id="tong-quan-ve-hoic" tabindex="-1">Tổng quan về HOIC <a class="header-anchor" href="#tong-quan-ve-hoic" aria-label="Permalink to &quot;Tổng quan về HOIC&quot;">​</a></h3><p>High Orbit Ion Cannon (HOIC) là một ứng dụng kiểm thử mạng miễn phí, mã nguồn mở được phát triển bởi Anonymous, một nhóm hacktivist, để thay thế cho Low Orbit Ion Cannon (LOIC). Được sử dụng cho tấn công từ chối dịch vụ (DoS) và tấn công từ chối dịch vụ phân tán (DDoS), nó hoạt động bằng cách tràn ngập hệ thống mục tiêu bằng các yêu cầu HTTP GET và POST rác.</p><h2 id="đang-nhap-vao-cac-may-ao" tabindex="-1">Đăng nhập vào các máy ảo <a class="header-anchor" href="#đang-nhap-vao-cac-may-ao" aria-label="Permalink to &quot;Đăng nhập vào các máy ảo&quot;">​</a></h2><p>Trước khi bắt đầu bài lab này, hãy bật và đăng nhập vào tất cả các máy ảo trong bài lab (Windows 7, 10, Server và Kali Linux).</p><p>Sao chép thư mục <strong>High Orbit Ion Cannon (HOIC)</strong> sang tất cả các máy ảo Windows (3 máy).</p><h2 id="cau-hinh-hoic" tabindex="-1">Cấu hình HOIC <a class="header-anchor" href="#cau-hinh-hoic" aria-label="Permalink to &quot;Cấu hình HOIC&quot;">​</a></h2><p>Chuyển sang Windows 10 và mở HOIC (hoic2.1.exe)</p><p>Trên giao diện GUI của HOIC, nhấp vào &#39;<strong>+</strong>&#39; để thêm mục tiêu.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ae12d7b7073ba34fd105724b932664d42326214a/hoic-1.png" alt="hoic-1"></p><p>Trên cửa sổ bật lên HOIC - [Target]:</p><ol><li>Nhập URL mục tiêu (địa chỉ IP của Kali)</li><li>Kéo thanh công suất lên <strong>High</strong></li><li>Chọn <strong>GenericBoost.hoic</strong> booster từ danh sách thả xuống</li><li>Nhấp <strong>add</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4d7add45a1ce5bb52c475b1419b2747fca8ce61d/hoic-4.png" alt="hoic-2"></li></ol><p>Đặt giá trị <strong>THREADS</strong> thành <strong>20</strong> như hình dưới:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ae12d7b7073ba34fd105724b932664d42326214a/hoic-3.png" alt="hoic-3"></p><p><strong>Bây giờ lặp lại quy trình này trên mỗi máy ảo Windows trong lab của bạn</strong>.</p><h2 id="thuc-hien-tan-cong-ddos" tabindex="-1">Thực hiện tấn công DDoS <a class="header-anchor" href="#thuc-hien-tan-cong-ddos" aria-label="Permalink to &quot;Thực hiện tấn công DDoS&quot;">​</a></h2><p>Khi HOIC đã được cấu hình trên tất cả các máy, chuyển sang từng máy và nhấp vào <strong>FIRE TEH LAZER!</strong>.</p><p align="center"><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4a96be03755e00ce6123ea2f6b022b77488744ec/hoic-5.png"></p> Điều này bắt đầu cuộc tấn công DDoS trên mục tiêu (Kali Linux). <p>Chuyển sang <strong>Kali Linux</strong> và khởi chạy <strong>Wireshark</strong>.</p><p>Quan sát rằng Wireshark bắt đầu bắt một lượng gói tin rất lớn, điều này có nghĩa là máy đang trải qua một số lượng lớn gói tin đến. Các gói tin này đến từ các máy ảo <strong>Windows 7, Windows Server và Windows 10</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4a96be03755e00ce6123ea2f6b022b77488744ec/hoic-6.png" alt="hoic-6"></p><p>Trong bài lab này, chỉ có ba máy được trình bày để tràn ngập một máy duy nhất. Nếu có một số lượng lớn máy thực hiện tràn ngập, thì tài nguyên của Kali Linux mục tiêu sẽ bị tiêu thụ hoàn toàn và máy bị quá tải.</p><p>Trong thực tế, một nhóm tin tặc vận hành hàng trăm hoặc hàng nghìn máy cấu hình công cụ này trên máy của họ, và mô phỏng cuộc tấn công DDoS bằng cách tràn ngập một máy/trang web mục tiêu cùng một lúc. Mục tiêu bị quá tải và ngừng phản hồi yêu cầu của người dùng hoặc bắt đầu loại bỏ các gói tin đến từ người dùng hợp lệ. Số lượng máy tấn công càng lớn, tác động của cuộc tấn công lên máy/trang web mục tiêu càng cao.</p><p>Để dừng DDoS, nhấp vào <strong>FIRE TEH LAZER!</strong> một lần nữa, sau đó đóng cửa sổ HOIC trên tất cả các máy ảo tấn công.</p>',30)]))}const d=t(o,[["render",h]]);export{m as __pageData,d as default};
